class Solution:
    def convertToTitle(self, columnNumber: int) -> str:
        result = []
        n = columnNumber
        power = 1
        # find highest power of 26 needed
        total = 0
        digits = []
        while n > 0:
            n -= 1
            digits.append(n % 26)
            n //= 26
        return ''.join(chr(ord('A') + d) for d in reversed(digits))

