class Solution:
    def convertToTitle(self, columnNumber: int) -> str:
        letters = []
        n = columnNumber
        while n:
            n -= 1
            letters.append(chr(ord('A') + n % 26))
            n //= 26
        return ''.join(reversed(letters))

