var convertToTitle = function(columnNumber) {
    let result = '';
    let n = columnNumber;
    while (n > 0) {
        n--;
        result = String.fromCharCode(65 + (n % 26)) + result;
        n = Math.floor(n / 26);
    }
    return result;
};
